def calculate_hfnc_failure_risk(p_roxi, p_roxv, hours):
    """
    Calculate the risk of HFNC failure based on p-ROXI and p-ROXV values.

    Parameters:
    p_roxi (float): The p-ROXI value.
    p_roxv (float): The p-ROXV value.
    hours (int): The number of hours since HFNC initiation (24 or 48).

    Returns:
    str: The risk of HFNC failure.
    """
    if hours == 24:
        if p_roxi >= 66.7 and p_roxv >= 24.0:
            return 'Low risk'
        elif p_roxi < 66.7 and p_roxv < 24.0:
            return 'High risk'
    elif hours == 48:
        if p_roxi >= 65.1 and p_roxv >= 24.6:
            return 'Low risk'
        elif p_roxi < 65.1 and p_roxv < 24.6:
            return 'High risk'
